    fun `GIVEN custom lists not present WHEN createMenu THEN custom lists menu item not created`() {
        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(mockSavedTag()) // item 2
            add(mockLikedTag()) // item 3
            add(mockA8CTag()) // item 4
        }

        val menu = helper.createMenu(tags)

        val customListsItem = menu.findSubMenu()
        assertThat(menu).doesNotContain(MenuElementData.Divider)
        assertThat(customListsItem).isNull()
    }

    @Test
    fun `GIVEN only one custom list WHEN createMenu THEN list shown directly in menu without submenu`() {
        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("my-list")) // item 2
        }

        val menu = helper.createMenu(tags)

        // Should not have a submenu
        assertThat(menu.findSubMenu()).isNull()

        // Should have divider and list item directly in menu
        assertThat(menu).contains(MenuElementData.Divider)
        val customListItem = menu.findSingleItem { it.id == "2" }!!
        assertThat(customListItem.text).isEqualTo(UiStringText("my-list"))
    }

    @Test
    fun `GIVEN two custom lists WHEN createMenu THEN lists shown directly in menu without submenu`() {
        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("list-1")) // item 2
            add(createCustomListTag("list-2")) // item 3
        }

        val menu = helper.createMenu(tags)

        // Should not have a submenu
        assertThat(menu.findSubMenu()).isNull()

        // Should have divider and list items directly in menu
        assertThat(menu).contains(MenuElementData.Divider)

        val customList1Item = menu.findSingleItem { it.id == "2" }!!
        assertThat(customList1Item.text).isEqualTo(UiStringText("list-1"))

        val customList2Item = menu.findSingleItem { it.id == "3" }!!
        assertThat(customList2Item.text).isEqualTo(UiStringText("list-2"))
    }

    @Test
    fun `GIVEN three custom lists WHEN createMenu THEN lists shown in submenu`() {
        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("list-1")) // item 2
            add(createCustomListTag("list-2")) // item 3
            add(createCustomListTag("list-3")) // item 4
        }

        val menu = helper.createMenu(tags)

        // Should have a submenu
        assertThat(menu).contains(MenuElementData.Divider)
        val customListsItem = menu.findSubMenu()!!
        assertThat(customListsItem.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_lists))

        // Lists should be inside the submenu
        val customList1Item = customListsItem.children.findSingleItem { it.id == "2" }!!
        assertThat(customList1Item.text).isEqualTo(UiStringText("list-1"))

        val customList2Item = customListsItem.children.findSingleItem { it.id == "3" }!!
        assertThat(customList2Item.text).isEqualTo(UiStringText("list-2"))

        val customList3Item = customListsItem.children.findSingleItem { it.id == "4" }!!
        assertThat(customList3Item.text).isEqualTo(UiStringText("list-3"))
    }"}

